class Playground {
    async run(inputs) {
        const vals = JSON.parse(inputs[0]);

        // 1. Initialization
        this.tree.init(vals);
        this.queue.init([]);
        this.currentLevel.init([]);
        this.vars.init([["level", 0], ["leftToRight", true]]);

        const root = this.tree.getRoot();
        if (!root) {
            this.log("Tree is empty.");
            return [];
        }

        const finalResult = [];
        let leftToRight = true;
        let levelCount = 0;

        this.queue.enqueue(root);
        this.log("Starting BFS traversal from root.");
        await this.await();

        while (!this.queue.isEmpty()) {
            const levelSize = this.queue.size();
            const currentLevelVals = [];
            this.currentLevel.init([]);

            this.vars.put("level", levelCount);
            this.vars.put("leftToRight", leftToRight);
            this.log(`Processing Level ${levelCount}. Zigzag direction: ${leftToRight ? 'L -> R' : 'R -> L'}`);
            await this.await();

            for (let i = 0; i < levelSize; i++) {
                const node = this.queue.dequeue();

                // Visual feedback: highlight node being processed
                this.tree.highlight(node.id, "#00e0ff");
                this.log(`Popped node ${node.val} from queue.`);

                currentLevelVals.push(node.val);
                this.currentLevel.push(node.val);
                await this.await();

                // Add children to queue for next level
                if (node.left) {
                    this.queue.enqueue(node.left);
                    this.log(`Queued left child: ${node.left.val}`);
                    await this.await();
                }
                if (node.right) {
                    this.queue.enqueue(node.right);
                    this.log(`Queued right child: ${node.right.val}`);
                    await this.await();
                }

                // Mark node as finished
                this.tree.highlight(node.id, "#00f5a0");
            }

            // Zigzag logic: if direction is right-to-left, reverse the collected array
            let processedLevel = [...currentLevelVals];
            if (!leftToRight) {
                this.log(`Direction is Right-to-Left: Reversing current level values [${processedLevel}]`);
                processedLevel.reverse();
                this.currentLevel.init(processedLevel);
                await this.await();
            }

            finalResult.push(processedLevel);
            this.log(`Level ${levelCount} completed. Adding [${processedLevel}] to result.`);

            // Flip direction and increment level
            leftToRight = !leftToRight;
            levelCount++;
            await this.await();
        }

        this.log("Traversal complete.");
        return finalResult;
    }
}
